; and may be inaccurate; treat them as hints, not verified annotation. Comments marked
; [DOC <manual> <page>] have been reconciled against the primary-source Microsoft SoftCard
; manuals (CP/M 2.20, (C) 1980) and are authoritative: S&HD = "Software and Hardware
; Details", CPMREF = the CP/M 2.2 Reference Manual. See the consolidated fact sheet at
; ../../docs/CPM_Manual_Reconcile_Facts.md. SCOPE: this is the 2.23 BIOS in the 60K config.
; The SoftCard I/O facts (config block, I/O Vector Table, Card Type Table, RPC cells) are
; SHARED across releases and carry the manual's 2.20 addresses unchanged. The 60K memory
; map / load addresses ($FA00 ORG, the $D300/$DCxx BDOS, etc.) are a POST-1980 config the
; manual does NOT document (it covers 44K and 56K only), so 60K-specific absolute addresses
; are flagged as outside the manual rather than cited to it; the device-6 / Pascal-1.1 probe
; is likewise a post-1980 extension absent from the 2.20 manual.

; Generated by disasm_z80
; Range:  $FA00-$FFFF  (1536 bytes)
;
; ===========================================================================
; 60K BIOS  -- the UNPATCHED TEMPLATE as shipped inside CPM60.COM
; ===========================================================================
; This is the BIOS exactly as it sits in the CPM60.COM installer payload (COM
; offset 0x2600, ORG $FA00) and on the disk's system tracks. It is the canonical
; *source* form: assembling it reproduces those 1536 bytes byte-for-byte, and it
; is the BIOS input to the CPM60.COM build.
;
; It is NOT quite what a booted image shows. The 6502 boot loader only COPIES the
; BIOS into the Language Card; it does not patch it. Instead the Z-80 cold-boot
; routine BIOS_BOOT ($FEEA) runs ONCE at cold start and self-modifies ~a few dozen
; bytes -- most visibly NOP-ing the $FA00 cold-boot JP here (JP BIOS_BOOT), since
; on the 60K system cold start is driven from the planted Z-80 reset; it also
; binds the console/RPC vectors ($FB37/$FCB9/$FB4A) to the installed card type.
; After it runs, the one-shot cold-boot region ($FEEA-$FF8D) is dead and the
; running system reuses it as scratch (so a captured snapshot shows ~147 bytes of
; $E5/$FF fill there -- those are NOT patches). What each self-mod does and why is
; catalogued in ../BOOT_AND_PATCHING.md section 3c. (BDOS is byte-identical in COM
; and booted; the CCP's only delta was the private-stack scratch at $DB5C.)
; ===========================================================================

    IFNDEF CPM60_LINK  ; [link] master defines CPM60_LINK and owns this; standalone keeps it
    DEVICE NOSLOT64K
    ENDIF

; -- External symbols --
WBOOT_VEC            EQU $0000               ; Warm-boot vector — JP WBOOT in BIOS. Touching it causes a CP/M warm boot.
IOBYTE               EQU $0003               ; [DOC S&HD 2-18] IOBYTE: logical-to-physical device map at $0003 -- four 2-bit fields,
                                              ; CONSOLE (bits 0-1), READER (bits 2-3), PUNCH (bits 4-5), LIST (bits 6-7); set via STAT or
                                              ; BDOS funcs 7/8. Each field's value selects which I/O Vector Table entry (#1 vs #2) is used.
CDISK                EQU $0004               ; Current drive (low nibble: 0=A, 1=B, ..., 15=P) and current user (high nibble, 0-15).
BDOS_VEC             EQU $0005               ; BDOS call vector — JP BDOS_ENTRY. Programs use CALL $0005 to invoke BDOS. Word at $0006 is also the top-of-TPA marker.
DEFAULT_DMA          EQU $0080               ; Default 128-byte DMA buffer. BDOS cold-init / DRV_ALLRESET (fn 13) set the DMA address here and WBOOT re-issues SETDMA($0080); sector/record I/O moves 128 bytes through it. At program load this same buffer doubles as the command tail: the first byte ($0080) holds the tail length (0-127) and the characters follow at $0081 (CMDLINE).
TPA_START            EQU $0100               ; Start of Transient Program Area. .COM files load here and execute starting at $0100.
SLOT_INFO_BASE       EQU $F3B8               ; [DOC S&HD 2-26/2-27] $F3B8 is the Disk Count Byte (number of disk controller cards x2);
                                              ; the Card Type Table (SLTTYP) proper starts at $F3B9, with slot S's entry at $F3B8+S
                                              ; (S=1..7). The cold-boot scan indexes this base by E (E=1..7) to read each slot's detected
                                              ; card type. Card type values: 0=no ROM, 1=unknown ROM, 2=Disk II, 3=Apple Comms/CCS 7710A
                                              ; serial, 4=Apple High-Speed Serial / Videx Videoterm / M&R Sup-R-Term / Silentype, 5=Parallel.

; -- Mid-instruction references (shown inline as cover+offset) --
;   $FB05 -> BIOS_WBOOT_3+1       z80 skip idiom: enters the operand of $3E at $FB04
;   $FB49 -> RPC_DISPATCH_1+1     shared instruction tail: $FB49 is reachable code inside the instruction at $FB48
;   $FEEB -> BIOS_BOOT+1          shared instruction tail: $FEEB is reachable code inside the instruction at $FEEA
;   $FEEC -> BIOS_BOOT+2          shared instruction tail: $FEEC is reachable code inside the instruction at $FEEA
;   $FEFA -> BIOS_BOOT_6+2        shared instruction tail: $FEFA is reachable code inside the instruction at $FEF8
;   $FEFC -> BIOS_BOOT_7+1        shared instruction tail: $FEFC is reachable code inside the instruction at $FEFB
;   $FF59 -> BIOS_BOOT_13+1       shared instruction tail: $FF59 is reachable code inside the instruction at $FF58

    IFNDEF CPM60_LINK  ; [link] master defines CPM60_LINK and owns this; standalone keeps it
    ORG $FA00
    ENDIF

BOOT:
        JP BIOS_BOOT                     ; $FA00  C3 EA FE
WBOOT:
        JP BIOS_WBOOT                    ; $FA03  C3 B8 FA
CONST:
        JP BIOS_CONST                    ; $FA06  C3 10 FB
CONIN:
        JP BIOS_CONIN                    ; $FA09  C3 1A FB
CONOUT:
        JP CONOUT_DISPATCH                    ; $FA0C  C3 4D FB
LIST:
        JP BIOS_LIST                     ; $FA0F  C3 70 FB
PUNCH:
        JP BIOS_PUNCH                    ; $FA12  C3 7F FB
READER:
        JP BIOS_READER                   ; $FA15  C3 91 FB
HOME:
        JP INIT_PASCAL_1_1_1             ; $FA18  C3 75 FE
SELDSK:
        JP SELDSK_IMPL_1                 ; $FA1B  C3 97 FE
SETTRK:
        JP INIT_PASCAL_1_1_4             ; $FA1E  C3 80 FE
SETSEC:
        JP BIOS_SETSEC                   ; $FA21  C3 F4 FB
SETDMA:
        JP BIOS_SETDMA                   ; $FA24  C3 F9 FB
READ:
        JP SELDSK_IMPL_3                 ; $FA27  C3 C6 FE
WRITE:
        JP SELDSK_IMPL_4                 ; $FA2A  C3 CC FE
LISTST:
        XOR A                            ; $FA2D  AF
        RET                              ; $FA2E  C9
        DEFB    $00                                              ; $FA2F
SECTRAN:
        LD H,B                           ; $FA30  60
        LD L,C                           ; $FA31  69
        RET                              ; $FA32  C9
DISK_PARAM_TBL:
        DEFS    8, $00    ; $FA33  fill
        DEFB    $FD,$FE,$73,$FA,$C5,$FF                          ; $FA3B
        DEFW    BIOS_BOOT_17             ; $FA41
        DEFS    8, $00    ; $FA43  fill
        DEFB    $FD,$FE,$73,$FA,$D1,$FF,$8F,$FF,$00,$00,$00,$00,$00,$00,$00,$00 ; $FA4B
        DEFB    $FD,$FE,$73,$FA,$DD,$FF                          ; $FA5B
        DEFW    HANDLER_TBL_FETCH               ; $FA61
        DEFS    8, $00    ; $FA63  fill
        DEFB    $FD,$FE,$73,$FA,$E9,$FF                          ; $FA6B
        DEFW    BANNER_RESTORE_A               ; $FA71
        DEFB    $20,$00,$03,$07,$00,$8B,$00,$2F,$00,$C0,$00,$0C,$00,$03,$00 ; $FA73
; [DOC S&HD 2-26/2-27] Cold-boot per-device init loop over the Card Type Table. The Card Type
;       Table (SLTTYP) starts at $F3B9, entry = $F3B8+S for slot S; $F3B8 itself is the Disk Count
;       Byte. The loop walks $F3B8+DE (DE=7..1 -> $F3BF..$F3B9), reading each slot's detected card
;       type and dispatching on it. (This is NOT the IOBYTE table -- IOBYTE is a single byte at $0003.)
SLOT_SCAN_INIT:
        LD DE,$0007                      ; $FA82  11 07 00
; [DOC S&HD 2-26] Loop body: reads the slot's Card Type Table value at $F3B8+DE. Card type 3
;       (Apple Communications / CCS 7710A serial) runs its init and stamps the entry; card type 4
;       (Apple High-Speed Serial / Videx Videoterm / M&R Sup-R-Term) takes the decremented branch
;       below that reclaims the $C800 firmware window.
SLOT_SCAN_INIT_1:
        LD HL,SLOT_INFO_BASE             ; $FA85  21 B8 F3
        ADD HL,DE                        ; $FA88  19
        LD A,(HL)                        ; $FA89  7E
        SUB $03                          ; $FA8A  D6 03
        JR NZ,SLOT_SCAN_INIT_2           ; $FA8C  20 07
        CALL SLOT_IOBASE_8E              ; $FA8E  CD 8A FE
        LD (HL),$03                      ; $FA91  36 03
        LD (HL),$15                      ; $FA93  36 15
; [DOC S&HD 2-26] Card-type-4 branch (Apple High-Speed Serial / Videx Videoterm / M&R Sup-R-Term):
;       runs INIT_PASCAL_1_0, then reclaims the shared $C800 expansion-ROM window (LD HL,$C800)
;       before continuing the per-slot Card Type Table scan. The card-type-2 sub-branch below
;       ($FAA3, CP $02 -> type-6) is the post-1980 Pascal-1.1 path NOT documented by the 2.20 manual.
SLOT_SCAN_INIT_2:
        DEC A                            ; $FA95  3D
        JR NZ,SLOT_SCAN_INIT_3           ; $FA96  20 0B
        CALL INIT_PASCAL_1_0             ; $FA98  CD 83 FD
        LD HL,$C800                      ; $FA9B  21 00 C8
        CALL RPC_DISPATCH                ; $FA9E  CD 45 FB
        JR SLOT_SCAN_INIT_4              ; $FAA1  18 0A
; [AI] Card-type dispatch continuation: after SUB $03 then DEC A, a remaining value of $02 means the
;       original Card Type Table byte was 6 -- the POST-1980 device-6 / Pascal-1.1 card class that
;       the 2.20 manual does NOT document (2.23 added a $Cn0B Pascal-1.1 probe that reassigns the
;       Videx from type 4 to type 6). Runs INIT_PASCAL_1_1 with the $0DD0 parameter. Not manual-backed.
SLOT_SCAN_INIT_3:
        CP $02                           ; $FAA3  FE 02
        JR NZ,SLOT_SCAN_INIT_4           ; $FAA5  20 06
        LD HL,$0DD0                      ; $FAA7  21 D0 0D
        CALL INIT_PASCAL_1_1             ; $FAAA  CD B0 FD
; [DOC S&HD 2-26/2-27] Loop tail of the Card Type Table scan: decrements the slot index E and repeats
;       for all seven Apple expansion slots (S=7..1), returning when done.
SLOT_SCAN_INIT_4:
        DEC E                            ; $FAAD  1D
        JR NZ,SLOT_SCAN_INIT_1           ; $FAAE  20 D5
        RET                              ; $FAB0  C9
SLOT_E000_ADDR:
        LD HL,$E000                      ; $FAB1  21 00 E0
        LD A,E                           ; $FAB4  7B
        OR H                             ; $FAB5  B4
        LD H,A                           ; $FAB6  67
RET_VECTOR:
        RET                              ; $FAB7  C9
; [AI] WBOOT (warm boot) entry: resets the Z-80 stack to $0080, re-establishes the 6502 console via
;       RPC, rescans the slots, then reloads/relaunches the CCP. NOTE: the BDOS sentinel at $DC08
;       and BDOS entry $DC06 are 60K-config absolute addresses -- a POST-1980 layout the 2.20 manual
;       (44K/56K only) does NOT document; do not read a manual address into them.
BIOS_WBOOT:
        LD SP,DEFAULT_DMA                ; $FAB8  31 80 00
        LD A,($E051)                     ; $FABB  3A 51 E0
        LD HL,$0E00                      ; $FABE  21 00 0E
        CALL RPC_DISPATCH                ; $FAC1  CD 45 FB
        CALL SLOT_SCAN_INIT              ; $FAC4  CD 82 FA
        LD A,($DC08)                     ; $FAC7  3A 08 DC
        CP $DC                           ; $FACA  FE DC
        JR Z,BIOS_WBOOT_1                ; $FACC  28 11
; [DOC S&HD 2-24/2-25] Warm-boot RPC setup: stores the 6502 call target at A$VEC=$F3D0, then loads
;       the SoftCard location from Z$CPU=$F3DE (low byte 0, high byte $0ENH for slot N) -- a WRITE
;       through that address is the CPU switch back to the 6502. ($000B/$77 here is 60K-specific glue.)
        LD HL,BIOS_BOOT_13+1             ; $FACE  21 59 FF
        LD ($F3D0),HL                    ; $FAD1  22 D0 F3
        LD HL,($F3DE)                    ; $FAD4  2A DE F3
        LD A,$77                         ; $FAD7  3E 77
        LD ($000B),A                     ; $FAD9  32 0B 00
        JP $000B                         ; $FADC  C3 0B 00
BIOS_WBOOT_1:
        XOR A                            ; $FADF  AF
        LD ($D307),A                     ; $FAE0  32 07 D3
; [AI] Cold-boot page-zero plant: writes JP WBOOT at $0000-$0002 and JP BDOS at $0005-$0007 (the
;       $0000 warm-boot vector and $0005 BDOS entry are SHARED CP/M architecture). The BDOS target
;       $DC06 stored at $0006 -- which also marks top-of-TPA -- is a 60K-config absolute address;
;       the 2.20 manual (44K/56K only) does NOT document this POST-1980 layout, so it is not cited.
BIOS_WBOOT_2:
        XOR A                            ; $FAE3  AF
        LD (BIOS_BOOT_5),A               ; $FAE4  32 F6 FE
        LD (BIOS_BOOT_3),A               ; $FAE7  32 F1 FE
        LD A,$C3                         ; $FAEA  3E C3
        LD (WBOOT_VEC),A                 ; $FAEC  32 00 00
        LD HL,WBOOT                      ; $FAEF  21 03 FA
        LD ($0001),HL                    ; $FAF2  22 01 00
        LD (BDOS_VEC),A                  ; $FAF5  32 05 00
        LD HL,$DC06                      ; $FAF8  21 06 DC
        LD ($0006),HL                    ; $FAFB  22 06 00
        LD BC,DEFAULT_DMA                ; $FAFE  01 80 00
        CALL BIOS_SETDMA                 ; $FB01  CD F9 FB
BIOS_WBOOT_3:
        LD A,$01                         ; $FB04  3E 01
        LD ($D74E),A                     ; $FB06  32 4E D7
        LD A,(CDISK)                     ; $FB09  3A 04 00
        LD C,A                           ; $FB0C  4F
        JP $D300                         ; $FB0D  C3 00 D3
; [DOC S&HD 2-18/2-19] CONST (console status) BIOS entry: jumps through I/O Vector Table cell 1,
;       $F380 (Console Status) -- the routine returns A=$FF if a console character is ready, $00
;       otherwise. This cell normally points into the BIOS and is user-patchable.
BIOS_CONST:
        LD HL,($F380)                    ; $FB10  2A 80 F3
        JP (HL)                          ; $FB13  E9
        DEFB    $3A                                              ; $FB14
CONST_VEC_PATCH:
        DEFB    $00,$E0,$17,$9F,$C9                              ; $FB15
; [DOC S&HD 2-17] CONIN (console input) BIOS entry: reads a raw key via CONIN_DISPATCH, masks the
;       high bit (AND $7F), then walks the Keyboard Character Redefinition Table to translate it.
;       Per the manual the table is at $F3AC; the code seeds HL=$F3AB and INC HL's to the first
;       entry's "from" byte at $F3AC. Up to six 2-byte entries (from-ASCII, to-ASCII, both high bit
;       clear); a byte with the high bit set terminates early (the JP M exit). Applies to TTY:/CRT:.
BIOS_CONIN:
        CALL CONIN_DISPATCH                    ; $FB1A  CD 5A FB
        AND $7F                          ; $FB1D  E6 7F
        LD HL,$F3AB                      ; $FB1F  21 AB F3
        LD B,$06                         ; $FB22  06 06
        LD C,A                           ; $FB24  4F
; [DOC S&HD 2-17] Keyboard-redefinition scan body: INC past to the "from" byte, test for the
;       high-bit-set terminator (JP M exits), else compare the input (in C) and on a match return
;       the redefined "to" byte (A=(HL)); loop up to six times via DJNZ.
KEY_REMAP_SCAN:
        INC HL                           ; $FB25  23
        LD A,(HL)                        ; $FB26  7E
        INC HL                           ; $FB27  23
        OR A                             ; $FB28  B7
        JP M,KBD_STROBE_CLEAR            ; $FB29  FA 31 FB
        CP C                             ; $FB2C  B9
        LD A,(HL)                        ; $FB2D  7E
        RET Z                            ; $FB2E  C8
        DJNZ KEY_REMAP_SCAN              ; $FB2F  10 F4
KBD_STROBE_CLEAR:
        LD A,C                           ; $FB31  79
        RET                              ; $FB32  C9
        DEFB    $11,$03,$00,$C3                                  ; $FB33
CONIN_HANDLER_VEC:
        DEFB    $39,$FB,$3A,$00,$E0,$17                          ; $FB37
        DEFW    SECTRAN                  ; $FB3D
        DEFB    $32,$10,$E0,$3F,$1F,$C9                          ; $FB3F
; [DOC S&HD 2-24/2-25] RPC dispatch: stores the 6502 subroutine address (in HL) at A$VEC=$F3D0
;       (low-high) -- the Z-80->6502 call vector -- before the SoftCard CPU-switch is triggered.
;       (The actual switch is a WRITE through Z$CPU=$F3DE; A$VEC just holds the target.)
RPC_DISPATCH:
        LD ($F3D0),HL                    ; $FB45  22 D0 F3
RPC_DISPATCH_1:
        LD (WBOOT_VEC),A                 ; $FB48  32 00 00
        RET                              ; $FB4B  C9
CONOUT_SET_C:
        LD C,A                           ; $FB4C  4F
; [DOC S&HD 2-18/2-19] CONOUT (console output) dispatch: masks the IOBYTE CONSOLE field (bits 0-1).
;       Value 2 = BAT: (RDR: in / LST: out), so console output is routed through I/O Vector Table
;       List Output #1 ($F392); any other value falls through to the screen-function escape processor.
CONOUT_DISPATCH:
        LD A,(IOBYTE)                    ; $FB4D  3A 03 00
        AND $03                          ; $FB50  E6 03
        CP $02                           ; $FB52  FE 02
        JR NZ,CONOUT_ESC_PROC         ; $FB54  20 4B
; [DOC S&HD 2-18/2-19] Jumps through I/O Vector Table List Output #1 cell ($F392) -- used for the
;       BAT: console-output case above; the char in C is carried to the line-printer device.
CONOUT_UC1:
        LD HL,($F392)                    ; $FB56  2A 92 F3
        JP (HL)                          ; $FB59  E9
; [DOC S&HD 2-18/2-19] CONIN dispatch: masks the IOBYTE CONSOLE field (bits 0-1). Value 2 (BAT:)
;       -> Reader Input #1 cell $F38A; value 3 (UC1:) -> Console Input #2 cell $F384; values 0/1
;       (TTY:/CRT:) -> Console Input #1 cell $F382. Each is a user-patchable I/O Vector Table cell.
CONIN_DISPATCH:
        LD A,(IOBYTE)                    ; $FB5A  3A 03 00
        AND $03                          ; $FB5D  E6 03
        CP $02                           ; $FB5F  FE 02
        LD HL,($F384)                    ; $FB61  2A 84 F3
        JR Z,CONIN_UC1                  ; $FB64  28 06
        JR NC,CONIN_VEC_JP                 ; $FB66  30 07
; [DOC S&HD 2-18/2-19] TTY:/CRT: console input via I/O Vector Table Console Input #1 cell ($F382).
CONIN_TTY:
        LD HL,($F382)                    ; $FB68  2A 82 F3
        JP (HL)                          ; $FB6B  E9
; [DOC S&HD 2-18/2-19] BAT: console input via I/O Vector Table Reader Input #1 cell ($F38A).
CONIN_UC1:
        LD HL,($F38A)                    ; $FB6C  2A 8A F3
CONIN_VEC_JP:
        JP (HL)                          ; $FB6F  E9
; [DOC S&HD 2-18/2-19] LIST (printer) output: masks the IOBYTE LIST field (bits 6-7; 0=TTY:, 1=CRT:,
;       2=LPT:, 3=UL1:). TTY:/CRT: return null; LPT: ($80) routes via CONOUT_UC1; UL1: ($C0) jumps
;       through the List Output #2 cell ($F394). (List Output #1 is $F392.) Char in C -> list device.
BIOS_LIST:
        LD A,(IOBYTE)                    ; $FB70  3A 03 00
        AND $C0                          ; $FB73  E6 C0
        CP $80                           ; $FB75  FE 80
        JR C,DEV_NULL_RET                  ; $FB77  38 27
        JR Z,CONOUT_UC1                  ; $FB79  28 DB
        LD HL,($F394)                    ; $FB7B  2A 94 F3
        JP (HL)                          ; $FB7E  E9
; [DOC S&HD 2-18/2-19] PUNCH output: masks the IOBYTE PUNCH field (bits 4-5). Value 1 (PTP:) ->
;       Punch Output #1 cell ($F38E); higher values -> Punch Output #2 cell ($F390); value 0 (TTY:)
;       returns null. The char in C is sent to the selected paper-tape-punch device.
BIOS_PUNCH:
        LD A,(IOBYTE)                    ; $FB7F  3A 03 00
        AND $30                          ; $FB82  E6 30
        CP $10                           ; $FB84  FE 10
        JR C,DEV_NULL_RET                  ; $FB86  38 18
        LD HL,($F38E)                    ; $FB88  2A 8E F3
        JR Z,CONIN_VEC_JP                  ; $FB8B  28 E2
        LD HL,($F390)                    ; $FB8D  2A 90 F3
        JP (HL)                          ; $FB90  E9
; [DOC S&HD 2-18/2-19] READER input: masks the IOBYTE READER field (bits 2-3; 0=TTY:, 1=CRT:,
;       2=PTR:, 3=UR2:). TTY:/CRT: -> CONIN_TTY (console input); PTR: ($08) -> CONIN_UC1; UR2: ($0C)
;       jumps through the Reader Input #2 cell ($F38C). (Reader Input #1 is $F38A.) Char returned in A.
BIOS_READER:
        LD A,(IOBYTE)                    ; $FB91  3A 03 00
        AND $0C                          ; $FB94  E6 0C
        CP $08                           ; $FB96  FE 08
        JR C,CONIN_TTY                  ; $FB98  38 CE
        JR Z,CONIN_UC1                  ; $FB9A  28 D0
        LD HL,($F38C)                    ; $FB9C  2A 8C F3
        JP (HL)                          ; $FB9F  E9
DEV_NULL_RET:
        SCF                              ; $FBA0  37
; [DOC S&HD 2-14] Console-output screen-function processor. $F3A2 is the Hardware-table lead-in
;       character (zero = no lead-in). Reached for the non-BAT: console path; tests the lead-in to
;       decide whether a multi-byte screen-function sequence is being emitted.
CONOUT_ESC_PROC:
        SBC A,A                          ; $FBA1  9F
        LD HL,$F3A2                      ; $FBA2  21 A2 F3
        LD L,(HL)                        ; $FBA5  6E
        INC L                            ; $FBA6  2C
        JP Z,CONSOLE_PUT_CHAR            ; $FBA7  CA A4 FC
        LD HL,L_FEE4                     ; $FBAA  21 E4 FE
        LD (HL),A                        ; $FBAD  77
        RES 7,C                          ; $FBAE  CB B9
        INC HL                           ; $FBB0  23
        LD A,(HL)                        ; $FBB1  7E
        OR A                             ; $FBB2  B7
        JP Z,CONOUT_SEQ_MATCH          ; $FBB3  CA 56 FC
        DEC (HL)                         ; $FBB6  35
; [DOC S&HD 2-14] Cursor-address coordinate handling: $F396 is SXYOFF, the Software cursor XY
;       coordinate offset (range 0-127; high bit 0 => Y first then X, high bit 1 => X first then Y).
        LD A,($F396)                     ; $FBB7  3A 96 F3
        LD HL,BIOS_BOOT_1                ; $FBBA  21 ED FE
        JR Z,COORD_SIGN_CHK                  ; $FBBD  28 0C
        OR A                             ; $FBBF  B7
        JP P,COORD_BIAS_SUB                  ; $FBC0  F2 C6 FB
        DEC HL                           ; $FBC3  2B
COORD_MASK7:
        AND $7F                          ; $FBC4  E6 7F
COORD_BIAS_SUB:
        LD E,A                           ; $FBC6  5F
        LD A,C                           ; $FBC7  79
        SUB E                            ; $FBC8  93
        LD (HL),A                        ; $FBC9  77
        RET                              ; $FBCA  C9
COORD_SIGN_CHK:
        OR A                             ; $FBCB  B7
        JP M,CURSOR_POSITION             ; $FBCC  FA D0 FB
        DEC HL                           ; $FBCF  2B
CURSOR_POSITION:
        CALL COORD_MASK7                    ; $FBD0  CD C4 FB
        LD HL,(BIOS_BOOT+2)              ; $FBD3  2A EC FE
; [DOC S&HD 2-14] $F3A1 is the Hardware cursor XY coordinate offset (the hardware-table counterpart
;       of SXYOFF=$F396); its high bit likewise selects X/Y vs Y/X transmission order to the terminal.
        LD A,($F3A1)                     ; $FBD6  3A A1 F3
        OR A                             ; $FBD9  B7
        JP P,EMIT_CURSOR_MOVE            ; $FBDA  F2 E2 FB
        AND $7F                          ; $FBDD  E6 7F
        LD E,L                           ; $FBDF  5D
        LD L,H                           ; $FBE0  6C
